return [{
  json: {
    workflow_id: 'CWF-220',
    vein: 'narrative_vein',
    dossier_id: $json.dossier_id || 'TEST-DOSSIER',
    script_draft_packet: $json.script_draft_packet || {},
    route_id: $json.route_id || 'ROUTE_PHASE1_STANDARD',
    execution_timestamp: new Date().toISOString(),
    critique_dimensions: ['hook_strength', 'structure_strength', 'evidence_support', 'retention_flow', 'governance_safety']
  }
}];

const draft = $json.script_draft_packet || {};
const draft_narrative = draft.payload?.narrative || {};

const hook_audit = {
  original_hook: draft_narrative.hook?.text || 'N/A',
  clarity_score: 0.65,
  curiosity_score: 0.72,
  emotional_pull_score: 0.58,
  overall_strength: 0.65,
  findings: [
    { issue: 'Opening lacks strong curiosity trigger', severity: 'MODERATE', recommendation: 'Lead with compelling question or surprising stat' },
    { issue: 'Emotional resonance could be stronger', severity: 'MODERATE', recommendation: 'Add relatable pain point or aspiration' }
  ],
  audit_result: 'NEEDS_IMPROVEMENT'
};

return [{
  json: {
    ...$json,
    hook_structure_audit: hook_audit,
    audit_phase: 'hook_complete'
  }
}];

const draft = $json.script_draft_packet || {};
const draft_narrative = draft.payload?.narrative || {};

const structure_assessment = {
  body_sections_count: draft_narrative.body?.sections?.length || 0,
  argument_flow_continuity: 0.78,
  section_transitions: 0.72,
  supporting_argument_strength: 0.68,
  overall_structure_strength: 0.73,
  findings: [
    { issue: 'Middle section lacks connective tissue between points', severity: 'MODERATE', recommendation: 'Add bridging sentences between arguments' },
    { issue: 'Supporting arguments need stronger evidence anchoring', severity: 'MODERATE', recommendation: 'Link each claim to specific data point' }
  ],
  audit_result: 'ACCEPTABLE_WITH_IMPROVEMENTS'
};

return [{
  json: {
    ...$json,
    structure_assessment: structure_assessment,
    audit_phase: 'structure_complete'
  }
}];

const draft = $json.script_draft_packet || {};
const evidence_section = draft.payload?.evidence || {};
const supporting_claims = evidence_section.supporting_claims || [];

const evidence_validation = {
  total_claims: supporting_claims.length,
  supported_claims: supporting_claims.filter(c => c.confidence >= 0.75).length,
  unsupported_claims: supporting_claims.filter(c => c.confidence < 0.75).length,
  overall_evidence_support: 0.71,
  findings: [],
  unsupported_claim_details: supporting_claims.filter(c => c.confidence < 0.75).map(c => ({
    claim: c.claim,
    confidence: c.confidence,
    gap_description: 'Insufficient evidence references or source citations',
    recommendation: 'Add supporting statistics, case studies, or expert attribution'
  })),
  audit_result: supporting_claims.filter(c => c.confidence < 0.75).length > 0 ? 'NEEDS_EVIDENCE_STRENGTHENING' : 'EVIDENCE_ADEQUATE'
};

return [{
  json: {
    ...$json,
    evidence_validation: evidence_validation,
    audit_phase: 'evidence_complete'
  }
}];

const draft = $json.script_draft_packet || {};
const word_count = draft.payload?.narrative?.body?.word_count || 0;

const retention_flow = {
  estimated_word_count: word_count,
  estimated_duration_minutes: Math.ceil(word_count / 130),
  engagement_arc_analysis: 'MODERATE_FLATNESS',
  pacing_issues: [
    { location: 'Middle section', issue: 'Information density drops', severity: 'MODERATE' },
    { location: 'Final third', issue: 'No clear call-to-action buildup', severity: 'MODERATE' }
  ],
  retention_prediction: 0.68,
  overall_retention_flow_strength: 0.68,
  findings: [
    { issue: 'Content loses momentum in middle sections', severity: 'MODERATE', recommendation: 'Add compelling data point or story element to regain engagement' },
    { issue: 'Closing does not create sense of urgency or transformation', severity: 'MODERATE', recommendation: 'Strengthen call-to-action with concrete next steps' }
  ],
  audit_result: 'NEEDS_PACING_REFINEMENT'
};

return [{
  json: {
    ...$json,
    retention_flow: retention_flow,
    audit_phase: 'retention_complete'
  }
}];

const governance_safety = {
  policy_compliance_check: 'APPROVED',
  brand_alignment_check: 'ALIGNED',
  sensitive_topic_flags: [],
  legal_risk_assessment: 'LOW',
  overall_governance_safety: 0.96,
  findings: [],
  audit_result: 'GOVERNANCE_APPROVED'
};

return [{
  json: {
    ...$json,
    governance_safety: governance_safety,
    audit_phase: 'governance_complete'
  }
}];

const draft = $json.script_draft_packet || {};
const hook_audit = $json.hook_structure_audit || {};
const structure = $json.structure_assessment || {};
const evidence = $json.evidence_validation || {};
const retention = $json.retention_flow || {};
const governance = $json.governance_safety || {};

const audit_scores = {
  hook_strength: hook_audit.overall_strength || 0,
  structure_strength: structure.overall_structure_strength || 0,
  evidence_support: evidence.overall_evidence_support || 0,
  retention_flow: retention.overall_retention_flow_strength || 0,
  governance_safety: governance.overall_governance_safety || 0
};

const average_score = Object.values(audit_scores).reduce((a, b) => a + b, 0) / Object.keys(audit_scores).length;

let debate_decision = 'APPROVED_FOR_REFINEMENT';
if (average_score < 0.60) {
  debate_decision = 'REJECTED';
} else if (hook_audit.overall_strength < 0.50 || evidence.overall_evidence_support < 0.60) {
  debate_decision = 'NEEDS_REWRITE';
}

const debate_packet = {
  instance_id: 'SDP-' + Date.now(),
  artifact_family: 'script_debate_packet',
  schema_version: '1.0.0',
  producer_workflow: 'SE-N8N-CWF-220-Script-Debate',
  dossier_ref: $json.dossier_id,
  created_at: new Date().toISOString(),
  status: 'CREATED',
  payload: {
    narrative: {
      original_draft: {
        title: draft.payload?.narrative?.title || 'N/A',
        hook: draft.payload?.narrative?.hook || {},
        body_summary: `${draft.payload?.narrative?.body?.sections?.length || 0} sections`,
        closing: draft.payload?.narrative?.closing || {}
      },
      critique_focus_areas: ['hook_strength', 'structure_strength', 'evidence_support', 'retention_flow', 'governance_safety']
    },
    context: {
      sourced_from_packet_id: draft.instance_id || 'UNKNOWN',
      original_topic_id: draft.payload?.context?.sourced_from?.topic_packet_id || 'UNKNOWN',
      original_research_id: draft.payload?.context?.sourced_from?.research_packet_id || 'UNKNOWN',
      debate_timestamp: new Date().toISOString(),
      debate_focus_areas: ['hook_strength', 'structure_strength', 'evidence_support', 'retention_flow', 'governance_safety']
    },
    evidence: {
      critique_points: [
        ...hook_audit.findings.map(f => ({finding: f.issue, severity: f.severity, recommendation: f.recommendation, dimension: 'hook_strength'})),
        ...structure.findings.map(f => ({finding: f.issue, severity: f.severity, recommendation: f.recommendation, dimension: 'structure_strength'})),
        ...evidence.findings.map(f => ({finding: f.issue, severity: f.severity, recommendation: f.recommendation, dimension: 'evidence_support'})),
        ...retention.findings.map(f => ({finding: f.issue, severity: f.severity, recommendation: f.recommendation, dimension: 'retention_flow'})),
        ...governance.findings.map(f => ({finding: f.issue, severity: f.severity, recommendation: f.recommendation, dimension: 'governance_safety'}))
      ],
      rejection_reasons: debate_decision === 'REJECTED' ? ['Critical quality metrics below minimum threshold (avg score: ' + average_score.toFixed(2) + ')'] : [],
      unsupported_claims: evidence.unsupported_claim_details || []
    },
    quality: {
      hook_strength_assessment: {
        clarity: hook_audit.clarity_score || 0,
        curiosity: hook_audit.curiosity_score || 0,
        emotional_pull: hook_audit.emotional_pull_score || 0,
        overall_strength: hook_audit.overall_strength || 0,
        audit_result: hook_audit.audit_result || 'UNKNOWN'
      },
      structure_strength_assessment: {
        argument_flow: structure.argument_flow_continuity || 0,
        section_transitions: structure.section_transitions || 0,
        supporting_strength: structure.supporting_argument_strength || 0,
        overall_strength: structure.overall_structure_strength || 0,
        audit_result: structure.audit_result || 'UNKNOWN'
      },
      evidence_support_assessment: {
        claim_coverage: evidence.overall_evidence_support || 0,
        unsupported_count: evidence.unsupported_claims || 0,
        audit_result: evidence.audit_result || 'UNKNOWN'
      },
      retention_flow_assessment: {
        engagement_arc: retention.engagement_arc_analysis || 'UNKNOWN',
        pacing_issues_count: retention.pacing_issues?.length || 0,
        overall_strength: retention.overall_retention_flow_strength || 0,
        audit_result: retention.audit_result || 'UNKNOWN'
      },
      governance_safety_assessment: {
        policy_compliance: governance.policy_compliance_check || 'UNKNOWN',
        legal_risk: governance.legal_risk_assessment || 'UNKNOWN',
        overall_assessment: governance.overall_governance_safety || 0,
        audit_result: governance.audit_result || 'UNKNOWN'
      },
      overall_debate_decision: debate_decision,
      average_quality_score: parseFloat(average_score.toFixed(3))
    },
    status: {
      debate_result: debate_decision,
      next_workflow: debate_decision === 'APPROVED_FOR_REFINEMENT' ? 'CWF-230' : 'WF-021',
      escalation_needed: average_score < 0.70,
      retry_possible: debate_decision !== 'REJECTED',
      decision_path: debate_decision === 'APPROVED_FOR_REFINEMENT' ? 'PROCEED_TO_REFINEMENT' : (debate_decision === 'REJECTED' ? 'REPLAY_WITH_MODIFICATIONS' : 'FULL_REWRITE')
    }
  }
};

return [{ json: debate_packet }];

const debate_packet = $json;
const payload = debate_packet.payload || {};

const validation_errors = [];

if (!payload.narrative || !payload.narrative.original_draft) validation_errors.push('Missing narrative.original_draft');
if (!payload.context || !payload.context.sourced_from_packet_id) validation_errors.push('Missing context.sourced_from_packet_id');
if (!payload.evidence || !Array.isArray(payload.evidence.critique_points)) validation_errors.push('Missing evidence.critique_points array');
if (!payload.quality || !payload.quality.overall_debate_decision) validation_errors.push('Missing quality.overall_debate_decision');
if (!payload.status || !payload.status.debate_result) validation_errors.push('Missing status.debate_result');

if (validation_errors.length > 0) {
  throw new Error('Debate packet validation failed: ' + validation_errors.join('; '));
}

return [{
  json: {
    ...debate_packet,
    validation_status: 'PASSED',
    validation_timestamp: new Date().toISOString()
  }
}];

const debate_packet = $json;
const payload = debate_packet.payload || {};

return [{
  json: {
    workflow_id: 'CWF-220',
    execution_status: 'SUCCESS',
    debate_result: payload.status.debate_result,
    next_workflow: payload.status.next_workflow,
    quality_score: payload.quality.average_quality_score,
    critique_count: payload.evidence.critique_points.length,
    debate_packet: debate_packet,
    dossier_delta: {
      namespace: 'script',
      mutation_type: 'append_debate_phase',
      target: 'dossier.script.cwf220_debate_output',
      value: {
        instance_id: debate_packet.instance_id,
        artifact_family: 'script_debate_packet',
        decision: payload.status.debate_result,
        timestamp: new Date().toISOString()
      },
      audit_entry: {
        timestamp: new Date().toISOString(),
        workflow_id: 'CWF-220',
        operation: 'CREATE_DEBATE_PACKET',
        lineage_intact: true,
        sourced_from: debate_packet.dossier_ref
      }
    },
    approval_delta: payload.status.debate_result !== 'APPROVED_FOR_REFINEMENT' ? {
      namespace: 'approval',
      mutation_type: 'append_to_queue',
      target: 'dossier.approval.pending_decisions',
      value: {
        decision_required: 'SCRIPT_DEBATE_ROUTING',
        packet_id: debate_packet.instance_id,
        owner_director: 'Krishna',
        decision_options: payload.status.debate_result === 'REJECTED' ? ['REPLAY_FROM_DISCOVERY', 'FULL_REWRITE'] : ['FULL_REWRITE'],
        timestamp: new Date().toISOString()
      }
    } : null,
    decision: payload.status.debate_result === 'APPROVED_FOR_REFINEMENT' ? 'PROCEED_TO_SCRIPT_REFINEMENT' : 'ROUTE_PHASE1_REPLAY'
  }
}];
